const body = $input.first().json.body || $input.first().json;
const agenda = body.unified_agenda;
const messages = agenda.channel_messages || [];
const email = messages.find(m => m.channel === 'email');
const telegram = messages.find(m => m.channel === 'telegram');
const whatsapp = messages.find(m => m.channel === 'whatsapp');
return [{
  json: {
    status: 'ready_to_send',
    source: 'n8n_unified_agenda',
    user_id: body.user_id,
    user_email: body.user_email,
    agenda_date: body.agenda_date,
    stats: agenda.stats,
    // In production connect these to Email/Telegram/WhatsApp nodes.
    email_message: email,
    telegram_message: telegram,
    whatsapp_message: whatsapp
  }
}];
